const errors = [];

function text(name) {
  return String(body[name] ?? '').trim();
}

function positiveNumber(name) {
  const raw = body[name];
  if (raw === undefined || raw === null || raw === '') return false;
  const n = Number(raw);
  return Number.isFinite(n) && n > 0;
}

function validDateText(name) {
  const value = text(name);
  if (!value) return false;
  const parsed = new Date(value.replace(' ', 'T'));
  return !Number.isNaN(parsed.getTime());
}

function dateWindowState() {
  const hasStart = text('start_date').length > 0;
  const hasEnd = text('end_date').length > 0;
  if (!hasStart && !hasEnd) return { provided: false, valid: false };
  if (!hasStart || !hasEnd) return { provided: true, valid: false, error: 'start_date y end_date deben enviarse juntos.' };
  if (!validDateText('start_date') || !validDateText('end_date')) return { provided: true, valid: false, error: 'start_date y end_date deben ser fechas v\u00e1lidas.' };
  const start = new Date(text('start_date').replace(' ', 'T'));
  const end = new Date(text('end_date').replace(' ', 'T'));
  if (start > end) return { provided: true, valid: false, error: 'start_date no puede ser mayor que end_date.' };
  return { provided: true, valid: true };
}

if (!text('email_to')) {
  errors.push('email_to es obligatorio para llamadas webhook.');
